#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=110,M=1010,Mod=31011;int n,m,fa[N],dep[N],stk[M][10],top[M],P[M],pp,num[M],res;
inline int fnd(const int &x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline int Fnd(const int &x){return fa[x]==x?x:Fnd(fa[x]);}
struct Edge{int u,v,w;inline bool operator<(const Edge &Q)const{return w<Q.w;};}G[M];
inline int Bfnd(int k){int l(1),r(pp),t(0),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1,t=m:r=m-1;return t;}
inline void dfs(const int &p,const int &nn,const int &I)
{
	if(p>top[I]){if(nn==num[I])++res;return;} dfs(p+1,nn,I);
	int U=Fnd(G[stk[I][p]].u),V=Fnd(G[stk[I][p]].v); if(U==V)return;
	if(dep[U]>dep[V]){int tmp=U;U=V;V=tmp;}bool fg=dep[U]==dep[V];
	dep[V]+=fg;fa[U]=V;dfs(p+1,nn+1,I);fa[U]=U;dep[V]-=fg;
}
int main()
{
	n=read();m=read();rep(1,m,i)G[i].u=read(),G[i].v=read(),G[i].w=read();int cnt=0;
	std::sort(G+1,G+m+1);rep(1,m,i)P[i]=G[i].w;pp=std::unique(P+1,P+m+1)-P-1;rep(1,m,i)G[i].w=Bfnd(G[i].w);
	rep(1,n,i)fa[i]=i;rep(1,m,i){int U=fnd(G[i].u),V=fnd(G[i].v);if(U==V)continue;fa[U]=V;++num[G[i].w];++cnt;}
	if(cnt!=n-1)return putchar('0'),0;rep(1,m,i)stk[G[i].w][++top[G[i].w]]=i;rep(1,n,i)fa[i]=i; 
	int ans=1,cur=1;rep(1,pp,i)
	{
		res=0;dfs(1,0,i);ans=1ll*ans*res%Mod;
		while(G[cur].w==i)
		{
			int U=Fnd(G[cur].u),V=Fnd(G[cur].v);++cur;if(U==V)continue;
			if(dep[U]>dep[V]){int tmp=U;U=V;V=tmp;} fa[U]=V;dep[V]+=dep[U]==dep[V];
		}
		
	}printf("%d\n",ans);return 0;
}
